void dfs(Graph g, int i, byte[] c) {

c[i] = grey;  // currently visiting i

for (Integer j : g.outEdges(i)) {

if (c[j] == white) {

c[j] = grey;

dfs(g, j, c);

}

}

c[i] = black; // done visiting i

